                    { field: 'body' as const, operation: 'containsAny' as const, values: ['total'], weight: 9 },
                  ],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Financial and monetary communications',
              decisionCriteria: ['Contains financial transactions'],
            },
          },
        },
        tuningParameters: {
          ...mockConfig.tuningParameters,
          KHigh: 1.5, // Multiplier for high confidence tier
        },
      };

      const testEmail = {
        ...mockEmail,
        subject: 'Receipt for your purchase order',
        bodyPlain: 'Total amount: $50',
      };

      const { session, result } = setupTest();
      result.emailId = testEmail.id;
      executeRuleScoring(testEmail, session, result, multiHighConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const receiptScore = financialResult?.subtypeScores.receipt;

      // Per SCORING_LOGIC.md: sum(high_match_weights) * KHigh
      // All 4 rules match: 12 + 11 + 10 + 9 = 42
      // 42 * 1.5 = 63
      const highMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'highConfidence') || [];
      expect(highMatches.length).toBe(4); // All matches included (not topK)

      // Verify score calculation: sum of weights * multiplier
      const highWeightSum = highMatches.reduce((sum, m) => sum + m.weight, 0);
      expect(highWeightSum).toBe(42); // 12 + 11 + 10 + 9
      expect(receiptScore?.totalScore).toBe(63); // 42 * 1.5
    });

    it('should apply multipliers to medium and low confidence tiers', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const receiptScore = financialResult?.subtypeScores.receipt;

      const mediumMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'mediumConfidence') || [];
      const lowMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'lowConfidence') || [];

      // Verify tiers are properly categorized
      if (mediumMatches.length > 0) {
        expect(mediumMatches[0].tier).toBe('mediumConfidence');
      }
      if (lowMatches.length > 0) {
        expect(lowMatches[0].tier).toBe('lowConfidence');
      }
    });

    it('should calculate tail support with dampening', () => {
      const multiSubtypeConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              receipt: {
                description: 'Receipt',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    { field: 'subject' as const, operation: 'containsAny' as const, values: ['receipt'], weight: 15 },
                  ],
                },
              },
              invoice: {
                description: 'Invoice',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    { field: 'subject' as const, operation: 'containsAny' as const, values: ['order'], weight: 12 },
                  ],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Financial and monetary communications',
              decisionCriteria: ['Contains financial transactions'],
            },
          },
        },
      };

      const testEmail = {
        ...mockEmail,
        subject: 'Receipt for order confirmation',
      };

      const { session, result } = setupTest();
      result.emailId = testEmail.id;
      executeRuleScoring(testEmail, session, result, multiSubtypeConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.scoringRationale[0]).toContain('primary:');

      // Should have both receipt and invoice subtypes with scores
      expect(Object.keys(financialResult?.subtypeScores || {})).toContain('receipt');
      expect(Object.keys(financialResult?.subtypeScores || {})).toContain('invoice');
    });
  });

  describe('Confidence Calculation', () => {
    it('should calculate confidence based on score and match count', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.confidence).toBeGreaterThan(0);
      expect(financialResult?.confidence).toBeLessThanOrEqual(95); // Capped at 95%
    });

    it('should return 0 confidence for zero scores', () => {
      const emptyEmail = {
        ...mockEmail,
        subject: 'No matching patterns',
        bodyPlain: 'No matching content',
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      // Start with empty scores
      result.scoreBreakdown.categoryScores = {};

      executeRuleScoring(emptyEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.confidence).toBe(0);
    });
  });

  describe('Subtype Selection', () => {
    it('should select highest scoring subtype', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.selectedSubtypeId).toBe('receipt');
    });

    it('should return null when no subtypes have scores', () => {
      const emptyEmail = {
        ...mockEmail,
        subject: 'No patterns',
        bodyPlain: 'No patterns',
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      executeRuleScoring(emptyEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.selectedSubtypeId).toBeNull();
    });
  });

  describe('Edge Cases and Error Handling', () => {
    it('should handle missing subject and body fields', () => {
      const incompleteEmail: EmailMessage = {
        ...mockEmail,
        subject: '', // Empty subject instead of undefined
        bodyPlain: undefined,
        bodyHtml: undefined,
      };

      const { session, result } = setupTest();
      result.emailId = incompleteEmail.id;
      executeRuleScoring(incompleteEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
    });

    it('should handle empty values arrays in rules', () => {
      const emptyValuesConfig = {
        ...mockConfig,
        topLevelCategories: {
          testCategory: {
            description: 'Test',
            subtypes: {
              emptyValues: {
                description: 'Test empty values',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject' as const,
                      operation: 'containsAny' as const,
                      values: [],
                      weight: 10,
                    },
                  ],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Test category',
              decisionCriteria: ['Test criteria'],
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, emptyValuesConfig);

      // Should handle gracefully without errors
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should handle subtypes without ruleBasedClassification', () => {
      const noRulesConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              noRules: {
                description: 'Subtype without rules',
                derived: false,
                parallelSafe: true,
                // No ruleBasedClassification
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Financial and monetary communications',
              decisionCriteria: ['Contains financial transactions'],
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, noRulesConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should handle unknown rule fields gracefully', () => {
      const unknownFieldConfig = {
        ...mockConfig,
        topLevelCategories: {
          testCategory: {
            description: 'Test',
            subtypes: {
              unknownField: {
                description: 'Test unknown field',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      // eslint-disable-next-line @typescript-eslint/no-explicit-any
                      field: 'unknownField' as any, // Test with invalid field (intentional for error handling test)
                      operation: 'containsAny' as const,
                      values: ['test'],
                      weight: 10,
                    },
                  ],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Test category',
              decisionCriteria: ['Test criteria'],
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, unknownFieldConfig);

      // Should not crash, should handle gracefully
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });
  });

  describe('Performance and Explainability', () => {
    it('should complete processing within reasonable time limits', () => {
      const startTime = Date.now();

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(1000); // Should complete in under 1 second
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeLessThan(1000);
    });

    it('should provide complete explainability information', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      for (const categoryResult of result.explainabilityTrace.ruleScoring) {
        if (Object.keys(categoryResult.subtypeScores).length > 0) {
          expect(categoryResult.scoringRationale.length).toBeGreaterThan(0);
          expect(categoryResult.ruleMatches).toBeDefined();

          for (const match of categoryResult.ruleMatches) {
            expect(match.field).toBeDefined();
            expect(match.operation).toBeDefined();
            expect(match.tier).toBeDefined();
            expect(match.matchedValue).toBeDefined();
            expect(match.ruleId).toBeDefined();
            expect(match.weight).toBeGreaterThan(0);
          }
        }
      }
    });

    it('should generate consistent results across multiple runs', () => {
      const { session: session1, result: result1 } = setupTest();
      result1.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session1, result1, mockConfig);

      const { session: session2, result: result2 } = setupTest();
      result2.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session2, result2, mockConfig);

      // Compare score breakdowns
      expect(result1.scoreBreakdown.categoryScores).toEqual(result2.scoreBreakdown.categoryScores);
      // Compare explainability traces
      expect(result1.explainabilityTrace.ruleScoring).toEqual(result2.explainabilityTrace.ruleScoring);
    });
  });

  describe('Integration with Classification Pipeline', () => {
    it('should preserve result structure correctly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      executeRuleScoring(mockEmail, session, result, mockConfig);

      // Should populate result with proper structure
      expect(result.scoreBreakdown.categoryScores).toBeDefined();
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should work with empty initial category scores', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      // Start with empty scores
      result.scoreBreakdown.categoryScores = {};

      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.scoreBreakdown.categoryScores).toBeDefined();
      expect(Object.keys(result.scoreBreakdown.categoryScores).length).toBeGreaterThan(0);
    });

    it('should handle large configuration files efficiently', () => {
      // Create a config with many categories and rules
      const largeConfig = {
        ...mockConfig,
        topLevelCategories: {},
      };

      // Generate 10 categories with 5 subtypes each
      for (let i = 0; i < 10; i++) {
        const categoryName = `category_${i}`;
        (largeConfig.topLevelCategories as Record<string, TopLevelCategory>)[categoryName] = {
          description: `Category ${i}`,
          subtypes: {},
          aiFinalClassification: {
            categoryDescription: `AI classification for category ${i}`,
            decisionCriteria: [`Criteria for category ${i}`],
          },
        };

        for (let j = 0; j < 5; j++) {
          const subtypeName = `subtype_${i}_${j}`;
          (largeConfig.topLevelCategories as Record<string, TopLevelCategory>)[categoryName].subtypes[subtypeName] = {
            description: `Subtype ${i} ${j}`,
            derived: false,
            parallelSafe: true,
            ruleBasedClassification: {
              highConfidence: [
                {
                  field: 'subject' as const,
                  operation: 'containsAny' as const,
                  values: [`pattern_${i}_${j}`],
                  weight: 10,
                },
              ],
            },
          };
        }
      }

      const startTime = Date.now();

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, largeConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(2000); // Should handle large configs efficiently
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });
  });
});

